import re
from pathlib import Path
from typing import NamedTuple

SCRIPT_DIR = Path(__file__).parent.resolve()
PROJECT_ROOT = SCRIPT_DIR.parent.parent
COMPONENT_DIR = PROJECT_ROOT / "Component"

AUTO_GENERATED_HEADER = """\
// <auto-generated>
// This code was generated by a tool.
// </auto-generated>

#nullable enable

"""


class Signature(NamedTuple):
    name: str
    modifier: str
    args: str
    arg_names: str
    return_type: str
    default_impl: str


def generate_components_card(signatures: list[Signature]) -> str:
    buffer = ""
    buffer += AUTO_GENERATED_HEADER
    buffer += """\
using System.Buffers;
using BaseLib.Abstracts;
using MegaCrit.Sts2.Core.Combat;
using MegaCrit.Sts2.Core.Commands.Builders;
using MegaCrit.Sts2.Core.Entities.Cards;
using MegaCrit.Sts2.Core.Entities.Creatures;
using MegaCrit.Sts2.Core.Entities.Merchant;
using MegaCrit.Sts2.Core.Entities.Players;
using MegaCrit.Sts2.Core.GameActions.Multiplayer;
using MegaCrit.Sts2.Core.Map;
using MegaCrit.Sts2.Core.Models;
using MegaCrit.Sts2.Core.Rewards;
using MegaCrit.Sts2.Core.Rooms;
using MegaCrit.Sts2.Core.ValueProps;
using MinionLib.Component.Core;
using MinionLib.Component.Interfaces;
using System.ComponentModel;

namespace MinionLib.Component;

#pragma warning disable CS0809
"""
    buffer += "public abstract partial class ComponentsCardModel\n{\n"
    for signature in signatures:
        args: str
        (name, modifier, args, arg_names, return_type, default_impl) = signature
        Xxx = f"""\
    [EditorBrowsable(EditorBrowsableState.Never)]
    [Obsolete("This member is sealed. Try adding `ComponentContext componentContext` as the last parameter, or disable this warning if intended.", false)]
    {modifier} sealed override {"async " if return_type == "Task" else ""}{return_type} {name}({args[:-2] if args.endswith(", ") else args})
    {{
        EnsureComponentsInitialized();

        var componentContext = new ComponentContext(ComponentPhase.Init);
        
        var count = Components.Count;
        var snapshot = ArrayPool<ICardComponent>.Shared.Rent(count);
        for (var i = 0; i < count; i++)
        {{
            snapshot[i] = Components[i];
        }}
        
        try
        {{
            for (var transitions = 0;
                 transitions < MaxPhaseTransitions && componentContext.Phase != ComponentPhase.Final;
                 transitions++)
            {{
                componentContext.MoveNextPhase();

                switch (componentContext.Phase)
                {{
                    case ComponentPhase.Prefix:
                        for(var i = 0; i < count; i++)
                        {{
                            var component = snapshot[i];
                            if (component.ComponentsCard != this) continue;
                            {"await " if return_type == "Task" else ""}component.{name}Prefix({arg_names}componentContext);
                            if (componentContext.Phase != ComponentPhase.Prefix) break;
                        }}

                        break;
                    case ComponentPhase.Postfix:
                        for(var i = count - 1; i >= 0; i--)
                        {{
                            var component = snapshot[i];
                            if(component.ComponentsCard != this) continue;
                            {"await " if return_type == "Task" else ""}component.{name}Postfix({arg_names}componentContext);
                            if (componentContext.Phase != ComponentPhase.Postfix) break;
                        }}

                        break;
                    case ComponentPhase.Prime:
                    case ComponentPhase.Core:
                    case ComponentPhase.Final:
                        {"await " if return_type == "Task" else ""}{name}Phased({arg_names}componentContext);
                        break;
                    case ComponentPhase.Init:
                    default:
                        throw new ArgumentOutOfRangeException();
                }}
            }}

            if (componentContext.Phase != ComponentPhase.Final)
                HandlePhaseTransitionLimitExceeded(componentContext.Phase);
        }}
        finally
        {{
            ArrayPool<ICardComponent>.Shared.Return(snapshot, clearArray: true);
        }}
    }}

"""
        XxxPhased = f"""\
    protected virtual {return_type} {name}Phased({args}ComponentContext componentContext)
    {{
        if (componentContext.Phase == ComponentPhase.Core)
            {"return " if return_type == "Task" else ""}{name}({arg_names}componentContext);

{default_impl}    }}

"""
        XxxNew = f"""\
    protected virtual {return_type} {name}({args}ComponentContext componentContext)
    {{
{default_impl}    }}
    
"""
        buffer += Xxx + XxxPhased + XxxNew
    buffer += "}\n"
    return buffer


