def generate_timing_enum(signatures: list[Signature]) -> str:
    buffer = ""
    buffer += AUTO_GENERATED_HEADER
    buffer += "namespace MinionLib.Component.Utils;\n\n"
    buffer += "public enum Timing\n"
    buffer += "{\n"
    for s in signatures:
        buffer += f"    {s.name},\n"
    buffer += "}\n"
    return buffer


def build_timing_ctx(args: list[str], timing: str) -> str:
    buffer = ""
    buffer += "var ctx = new OnTimingContext(\n"
    buffer += f"                Timing.{timing}{',' if args else ''}\n"
    for i in args:
        a = i[0].upper() + i[1:]
        buffer += f"                {a}: {i}{',' if i != args[-1] else ''}\n"
    buffer += "            );\n"
    return buffer


